import 'package:flutter/material.dart';
class PiyiTextField extends StatelessWidget{const PiyiTextField({super.key,required this.controller,required this.label,this.hint,this.icon,this.keyboardType,this.maxLines=1,this.obscureText=false});final TextEditingController controller;final String label;final String? hint;final IconData? icon;final TextInputType? keyboardType;final int maxLines;final bool obscureText;@override Widget build(BuildContext context)=>TextField(controller:controller,keyboardType:keyboardType,maxLines:maxLines,obscureText:obscureText,decoration:InputDecoration(labelText:label,hintText:hint,prefixIcon:icon==null?null:Icon(icon)));}
